              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : chartData.length === 0 ? (
          <div
            className="flex h-full items-center justify-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#b0b0a8",
            }}
          >
            No data yet
          </div>
        ) : (
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={chartData}
              margin={{ top: 4, right: 0, bottom: 0, left: -20 }}
              barGap={1}
              barCategoryGap="20%"
            >
              <CartesianGrid
                strokeDasharray="3 3"
                stroke="#f0f0ed"
                vertical={false}
              />
              <XAxis
                dataKey="label"
                tick={{ fontSize: 10, fill: "#b0b0a8" }}
                tickLine={false}
                axisLine={{ stroke: "#e8e8e5" }}
                interval="preserveStartEnd"
              />
              <YAxis
                tick={{ fontSize: 10, fill: "#b0b0a8" }}
                tickLine={false}
                axisLine={false}
                allowDecimals={false}
              />
              <Tooltip
                contentStyle={{
                  fontFamily: "var(--font-dm-sans)",
                  fontSize: "12px",
                  borderRadius: "6px",
                  border: "1px solid #e8e8e5",
                  boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
                }}
                labelStyle={{ fontWeight: 600, color: "#111113" }}
                cursor={{ fill: "rgba(0,0,0,0.03)" }}
              />
              <Bar
                dataKey="releases"
                name="Releases"
                fill="#e8601a"
                radius={[2, 2, 0, 0]}
                maxBarSize={20}
              />
              <Bar
                dataKey="semantic_releases"
                name="AI Reports"
                fill="#f4a261"
                radius={[2, 2, 0, 0]}
                maxBarSize={20}
              />
            </BarChart>
          </ResponsiveContainer>
        )}
      </div>
    </div>
  );
}

