   102→          fontSize: "24px",
   103→          fontWeight: 700,
   104→          color: "#111113",
   105→        }}
   106→      >
   107→        Semantic Releases
   108→      </h1>
   109→
   110→      {/* Project filter */}
   111→      <div>
   112→        <select
   113→          value={projectFilter}
   114→          onChange={(e) => {
