   116→            setPage(1);
   117→          }}
   118→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   119→          style={{
   120→            fontFamily: "var(--font-dm-sans)",
   121→            fontSize: "13px",
   122→            color: "#111113",
   123→            border: "1px solid #e8e8e5",
   124→          }}
   125→          onFocus={(e) =>
   126→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   127→          }
   128→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   129→        >
   130→          <option value="all">All Projects</option>
   131→          {projectsData?.data.map((p: Project) => (
   132→            <option key={p.id} value={p.id}>
   133→              {p.name}
   134→            </option>
   135→          ))}
   136→        </select>
   137→      </div>
   138→
   139→      {/* Table card */}
   140→      <div
   141→        className="overflow-hidden rounded-lg bg-white"
   142→        style={{ border: "1px solid #e8e8e5" }}
   143→      >
   144→        {isLoading ? (
   145→          <div
   146→            className="py-16 text-center"
   147→            style={{
   148→              fontFamily: "var(--font-dm-sans)",
   149→              fontSize: "13px",
   150→              color: "#6b7280",
   151→            }}
   152→          >
   153→            Loading...
   154→          </div>
   155→        ) : releases.length === 0 ? (
   156→          <div className="py-16 text-center">
   157→            <p
   158→              style={{
   159→                fontFamily: "var(--font-fraunces)",
   160→                fontStyle: "italic",
   161→                fontSize: "15px",
   162→                color: "#9ca3af",
   163→              }}
   164→            >
   165→              No semantic releases yet
   166→            </p>
   167→          </div>
   168→        ) : (
   169→          <table className="w-full">
   170→            <thead>
   171→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   172→                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   173→                  (col) => (
   174→                    <th
   175→                      key={col}
   176→                      className="px-4 py-3 text-left"
   177→                      style={{
   178→                        fontFamily: "var(--font-dm-sans)",
   179→                        fontSize: "11px",
   180→                        fontWeight: 600,
   181→                        textTransform: "uppercase" as const,
   182→                        letterSpacing: "0.08em",
   183→                        color: "#9ca3af",
   184→                      }}
   185→                    >
   186→                      {col}
   187→                    </th>
   188→                  )
   189→                )}
   190→              </tr>
   191→            </thead>
   192→            <tbody>
   193→              {releases.map((sr) => {
   194→                const project = projectsById.get(sr.project_id);
   195→                return (
   196→                  <tr
   197→                    key={sr.id}
   198→                    className="transition-colors hover:bg-[#fafaf9]"
   199→                    style={{ borderBottom: "1px solid #e8e8e5" }}
   200→                  >
   201→                    {/* Project */}
   202→                    <td className="px-4 py-3">
   203→                      {project ? (
   204→                        <Link
   205→                          href={`/projects/${project.id}`}
   206→                          className="hover:underline"
