   210→                            color: "#111113",
   211→                            fontWeight: 500,
   212→                          }}
   213→                        >
   214→                          {project.name}
   215→                        </Link>
   216→                      ) : (
   217→                        <span
   218→                          style={{
   219→                            fontFamily: "var(--font-dm-sans)",
   220→                            fontSize: "13px",
   221→                            color: "#9ca3af",
   222→                          }}
   223→                        >
   224→                          {"\u2014"}
   225→                        </span>
   226→                      )}
   227→                    </td>
   228→
   229→                    {/* Version */}
   230→                    <td className="px-4 py-3">
   231→                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
   232→                        <VersionChip version={sr.version} />
   233→                      </Link>
   234→                    </td>
   235→
   236→                    {/* Status */}
   237→                    <td className="px-4 py-3">
   238→                      <span
   239→                        className="text-[13px] font-medium"
   240→                        style={{
   241→                          fontFamily: "var(--font-dm-sans)",
   242→                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
   243→                        }}
   244→                      >
   245→                        {sr.status}
   246→                      </span>
   247→                    </td>
   248→
   249→                    {/* Urgency */}
   250→                    <td className="px-4 py-3">
   251→                      {sr.report?.urgency ? (
   252→                        <UrgencyChip urgency={sr.report.urgency} />
   253→                      ) : (
   254→                        <span
   255→                          style={{
   256→                            fontFamily: "var(--font-dm-sans)",
   257→                            fontSize: "13px",
   258→                            color: "#9ca3af",
   259→                          }}
   260→                        >
   261→                          {"\u2014"}
   262→                        </span>
   263→                      )}
   264→                    </td>
   265→
   266→                    {/* Age */}
   267→                    <td className="px-4 py-3">
   268→                      <span
   269→                        style={{
   270→                          fontFamily: "var(--font-dm-sans)",
   271→                          fontSize: "13px",
   272→                          color: "#9ca3af",
   273→                        }}
   274→                      >
   275→                        {timeAgo(sr.completed_at ?? sr.created_at)}
   276→                      </span>
   277→                    </td>
   278→
   279→                    {/* Delete */}
   280→                    <td className="px-4 py-3">
   281→                      <button
   282→                        onClick={() => setDeletingId(sr.id)}
   283→                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
   284→                        style={{ color: "#9ca3af" }}
   285→                        title="Delete semantic release"
   286→                      >
   287→                        <Trash2 className="h-4 w-4" />
   288→                      </button>
   289→                    </td>
   290→                  </tr>
   291→                );
   292→              })}
   293→            </tbody>
   294→          </table>
   295→        )}
   296→      </div>
   297→
   298→      {/* Pagination */}
   299→      {total > 0 && (
   300→        <div className="flex items-center justify-between">
   301→          <span
   302→            style={{
   303→              fontFamily: "var(--font-dm-sans)",
   304→              fontSize: "13px",
   305→              color: "#9ca3af",
   306→            }}
   307→          >
   308→            {startRow}&ndash;{endRow} of {total}
   309→          </span>
   310→          <div className="flex items-center gap-2">
   311→            <button
   312→              disabled={page <= 1}
   313→              onClick={() => setPage(page - 1)}
   314→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   315→              style={{
   316→                fontFamily: "var(--font-dm-sans)",
   317→                fontSize: "13px",
   318→                color: "#374151",
   319→                border: "1px solid #e8e8e5",
   320→              }}
   321→            >
   322→              Previous
   323→            </button>
   324→            <button
   325→              disabled={page >= totalPages}
   326→              onClick={() => setPage(page + 1)}
   327→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   328→              style={{
   329→                fontFamily: "var(--font-dm-sans)",
   330→                fontSize: "13px",
   331→                color: "#374151",
   332→                border: "1px solid #e8e8e5",
   333→              }}
   334→            >
   335→              Next
   336→            </button>
   337→          </div>
   338→        </div>
   339→      )}
   340→
   341→      {/* Delete confirmation */}
   342→      <ConfirmDialog
   343→        open={!!deletingId}
   344→        onOpenChange={(open) => {
   345→          if (!open) setDeletingId(null);
   346→        }}
   347→        title="Delete Semantic Release"
   348→        description="This will permanently delete this semantic release and its report."
   349→        onConfirm={async () => {
   350→          if (deletingId) {
   351→            await srApi.delete(deletingId);
   352→            mutateData();
   353→          }
   354→        }}
   355→      />
   356→    </div>
   357→  );
   358→}
