     2→"use client";
     3→
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import {
     7→  projects as projectsApi,
     8→  releases as releasesApi,
     9→  sources as sourcesApi,
    10→  semanticReleases as srApi,
    11→} from "@/lib/api/client";
    12→import { VersionChip } from "@/components/ui/version-chip";
    13→import { getProviderIcon } from "@/components/ui/provider-badge";
    14→import { Sparkles } from "lucide-react";
    15→import type { Release, SemanticRelease, Source } from "@/lib/api/types";
    16→import { timeAgo } from "@/lib/format";
    17→
    18→type FeedItemType =
    19→  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
    20→  | { kind: "semantic"; data: SemanticRelease; projectName?: string };
    21→
    22→function getTimestamp(item: FeedItemType): number {
    23→  if (item.kind === "release") {
    24→    return new Date(item.data.released_at ?? item.data.created_at).getTime();
    25→  }
    26→  return new Date(item.data.created_at).getTime();
    27→}
    28→
    29→function getTimeStr(item: FeedItemType): string {
    30→  if (item.kind === "release") {
    31→    return item.data.released_at ?? item.data.created_at;
    32→  }
    33→  return item.data.created_at;
    34→}
    35→
    36→export function UnifiedFeed() {
    37→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    38→    projectsApi.list()
    39→  );
    40→
    41→  const { data: feedItems, isLoading } = useSWR(
    42→    projectsData ? "unified-feed" : null,
    43→    async () => {
    44→      if (!projectsData?.data?.length) return [];
    45→
    46→      const projectMap = new Map(
    47→        projectsData.data.map((p) => [p.id, p.name])
    48→      );
    49→      const projectSlice = projectsData.data.slice(0, 10);
    50→
    51→      // Fetch releases, sources, and semantic releases in parallel
    52→      const [releaseResults, sourceResults, srResults] = await Promise.all([
    53→        Promise.all(
    54→          projectSlice.map((p) =>
    55→            releasesApi.listByProject(p.id, 1).catch(() => null)
    56→          )
    57→        ),
    58→        Promise.all(
    59→          projectSlice.map((p) =>
    60→            sourcesApi.listByProject(p.id, 1).catch(() => null)
    61→          )
    62→        ),
    63→        Promise.all(
    64→          projectSlice.map((p) =>
    65→            srApi.list(p.id, 1).catch(() => null)
    66→          )
    67→        ),
    68→      ]);
    69→
    70→      // Build source lookup maps
    71→      const sourceMap = new Map<string, string>();
    72→      const providerMap = new Map<string, string>();
    73→      const sourceProjectMap = new Map<string, string>();
    74→      sourceResults
    75→        .filter((r): r is NonNullable<typeof r> => r !== null)
    76→        .flatMap((r) => r.data)
    77→        .forEach((s: Source) => {
    78→          sourceMap.set(s.id, s.repository);
    79→          providerMap.set(s.id, s.provider);
    80→          sourceProjectMap.set(s.id, s.project_id);
    81→        });
    82→
    83→      // Build feed items
    84→      const items: FeedItemType[] = [];
    85→
    86→      releaseResults
    87→        .filter((r): r is NonNullable<typeof r> => r !== null)
    88→        .flatMap((r) => r.data)
    89→        .forEach((rel) => {
    90→          const projectId = sourceProjectMap.get(rel.source_id);
    91→          items.push({
    92→            kind: "release",
    93→            data: rel,
    94→            repository: sourceMap.get(rel.source_id),
    95→            provider: providerMap.get(rel.source_id),
    96→            projectName: projectId ? projectMap.get(projectId) : undefined,
    97→          });
    98→        });
    99→
   100→      srResults
   101→        .filter((r): r is NonNullable<typeof r> => r !== null)
   102→        .flatMap((r) => r.data)
   103→        .forEach((sr) => {
   104→          items.push({
   105→            kind: "semantic",
   106→            data: sr,
   107→            projectName: projectMap.get(sr.project_id),
   108→          });
   109→        });
   110→
   111→      // Sort by timestamp descending, take first 15
   112→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
   113→      return items.slice(0, 15);
   114→    }
   115→  );
   116→
   117→  if (isLoading) {
   118→    return (
   119→      <div
   120→        className="rounded-lg bg-white py-16 text-center"
   121→        style={{ border: "1px solid #e8e8e5" }}
   122→      >
   123→        <p
   124→          style={{
   125→            fontFamily: "var(--font-dm-sans)",
   126→            fontSize: "13px",
   127→            color: "#6b7280",
