   131→        </p>
   132→      </div>
   133→    );
   134→  }
   135→
   136→  if (!feedItems || feedItems.length === 0) {
   137→    return null; // Empty state handled by parent
   138→  }
   139→
   140→  return (
   141→    <div
   142→      className="flex flex-col rounded-lg bg-white"
   143→      style={{ border: "1px solid #e8e8e5", height: "280px" }}
   144→    >
   145→      {/* Header */}
   146→      <div
   147→        className="flex items-center justify-between px-5 py-4 shrink-0"
   148→        style={{ borderBottom: "1px solid #e8e8e5" }}
   149→      >
   150→        <h3
   151→          className="font-medium"
   152→          style={{
   153→            fontFamily: "var(--font-dm-sans)",
   154→            fontSize: "13px",
   155→            color: "#111113",
   156→          }}
   157→        >
   158→          Recent Activity
   159→        </h3>
   160→        <div className="flex items-center gap-3">
   161→          <Link
   162→            href="/releases"
   163→            className="text-sm hover:underline"
   164→            style={{
   165→              fontFamily: "var(--font-dm-sans)",
   166→              fontSize: "12px",
   167→              color: "#6b7280",
   168→            }}
   169→          >
   170→            Releases
   171→          </Link>
   172→          <span style={{ color: "#e8e8e5" }}>|</span>
   173→          <Link
   174→            href="/semantic-releases"
   175→            className="text-sm hover:underline"
   176→            style={{
   177→              fontFamily: "var(--font-dm-sans)",
   178→              fontSize: "12px",
   179→              color: "#6b7280",
   180→            }}
   181→          >
   182→            Intelligence
   183→          </Link>
   184→        </div>
   185→      </div>
   186→
   187→      {/* Feed items — scrollable */}
   188→      <div className="flex-1 overflow-y-auto">
   189→        {feedItems.map((item, idx) => (
   190→          <FeedEntry
   191→            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
   192→            item={item}
   193→            isLast={idx === feedItems.length - 1}
   194→          />
   195→        ))}
   196→      </div>
   197→    </div>
   198→  );
   199→}
