   201→function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
   202→  if (item.kind === "semantic") {
   203→    const sr = item.data;
   204→    const urgency = sr.report?.urgency?.toUpperCase();
   205→    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";
