   283→      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
   284→      style={{
   285→        borderBottom: isLast ? undefined : "1px solid #e8e8e5",
   286→      }}
   287→    >
   288→      {/* Provider icon */}
   289→      {Icon ? (
   290→        <Icon size={14} className="shrink-0" style={{ color: "#9ca3af" }} />
   291→      ) : (
   292→        <div className="h-3.5 w-3.5 shrink-0" />
   293→      )}
   294→
   295→      {/* Content */}
   296→      <div className="min-w-0 flex-1 flex items-center gap-2">
   297→        <span
   298→          className="truncate"
   299→          style={{
   300→            fontFamily: "'JetBrains Mono', monospace",
   301→            fontSize: "13px",
   302→            color: "#6b7280",
   303→          }}
   304→        >
   305→          {item.repository ?? release.source_id.slice(0, 12)}
   306→        </span>
   307→        {item.projectName && (
   308→          <span
   309→            className="truncate"
   310→            style={{
   311→              fontFamily: "var(--font-dm-sans)",
   312→              fontSize: "12px",
   313→              color: "#9ca3af",
   314→            }}
   315→          >
   316→            · {item.projectName}
   317→          </span>
   318→        )}
   319→      </div>
   320→
   321→      {/* Version + timestamp */}
   322→      <div className="flex items-center gap-3 shrink-0">
   323→        <VersionChip version={release.version} />
   324→        <span
   325→          className="whitespace-nowrap"
   326→          style={{
   327→            fontFamily: "var(--font-dm-sans)",
