import { getProviderIcon } from "@/components/ui/provider-badge";
import { Sparkles } from "lucide-react";
import type { Release, SemanticRelease, Source } from "@/lib/api/types";
import { timeAgo } from "@/lib/format";

type FeedItemType =
  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
  | { kind: "semantic"; data: SemanticRelease; projectName?: string };

function getTimestamp(item: FeedItemType): number {
  if (item.kind === "release") {
    return new Date(item.data.released_at ?? item.data.created_at).getTime();
  }
  return new Date(item.data.created_at).getTime();
}

function getTimeStr(item: FeedItemType): string {
  if (item.kind === "release") {
    return item.data.released_at ?? item.data.created_at;
  }
  return item.data.created_at;
}

function ProviderIcon({ provider }: { provider: string }) {
  const icon = getProviderIcon(provider);
  if (!icon) return <div className="h-3.5 w-3.5 shrink-0" />;
  return icon({ size: 14, className: "shrink-0", style: { color: "#9ca3af" } });
}

export function UnifiedFeed() {
  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    projectsApi.list()
  );

  const { data: feedItems, isLoading } = useSWR(
    projectsData ? "unified-feed" : null,
    async () => {
      if (!projectsData?.data?.length) return [];

      const projectMap = new Map(
        projectsData.data.map((p) => [p.id, p.name])
      );
      const projectSlice = projectsData.data.slice(0, 10);

      // Fetch releases, sources, and semantic releases in parallel
      const [releaseResults, sourceResults, srResults] = await Promise.all([
        Promise.all(
          projectSlice.map((p) =>
            releasesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
        Promise.all(
          projectSlice.map((p) =>
            sourcesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
        Promise.all(
          projectSlice.map((p) =>
            srApi.list(p.id, 1).catch(() => null)
          )
        ),
      ]);

      // Build source lookup maps
      const sourceMap = new Map<string, string>();
      const providerMap = new Map<string, string>();
      const sourceProjectMap = new Map<string, string>();
      sourceResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((s: Source) => {
          sourceMap.set(s.id, s.repository);
          providerMap.set(s.id, s.provider);
          sourceProjectMap.set(s.id, s.project_id);
        });

      // Build feed items
      const items: FeedItemType[] = [];

      releaseResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((rel) => {
          const projectId = sourceProjectMap.get(rel.source_id);
          items.push({
            kind: "release",
            data: rel,
            repository: sourceMap.get(rel.source_id),
            provider: providerMap.get(rel.source_id),
            projectName: projectId ? projectMap.get(projectId) : undefined,
          });
        });

      srResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((sr) => {
          items.push({
            kind: "semantic",
            data: sr,
            projectName: projectMap.get(sr.project_id),
          });
        });

      // Sort by timestamp descending, take first 15
      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
      return items.slice(0, 15);
    }
  );

  if (isLoading) {
    return (
      <div
        className="rounded-lg bg-white py-16 text-center"
        style={{ border: "1px solid #e8e8e5" }}
      >
        <p
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#6b7280",
          }}
        >
          Loading activity...
        </p>
      </div>
    );
  }

  if (!feedItems || feedItems.length === 0) {
    return null; // Empty state handled by parent
  }

  return (
    <div
      className="flex flex-col rounded-lg bg-white"
      style={{ border: "1px solid #e8e8e5", height: "280px" }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-4 shrink-0"
        style={{ borderBottom: "1px solid #e8e8e5" }}
      >
        <h3
          className="font-medium"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#111113",
          }}
        >
          Recent Activity
        </h3>
        <div className="flex items-center gap-3">
          <Link
            href="/releases"
            className="text-sm hover:underline"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#6b7280",
            }}
          >
            Releases
          </Link>
          <span style={{ color: "#e8e8e5" }}>|</span>
          <Link
            href="/semantic-releases"
            className="text-sm hover:underline"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#6b7280",
            }}
          >
            Intelligence
          </Link>
        </div>
      </div>

      {/* Feed items — scrollable */}
      <div className="flex-1 overflow-y-auto">
        {feedItems.map((item, idx) => (
          <FeedEntry
            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
            item={item}
            isLast={idx === feedItems.length - 1}
          />
        ))}
      </div>
    </div>
  );
}

function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
  if (item.kind === "semantic") {
    const sr = item.data;
    const urgency = sr.report?.urgency?.toUpperCase();
    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";

    return (
      <Link
        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
        className="flex items-center gap-3 px-5 py-2.5 transition-colors hover:bg-[#fafaf9]"
        style={{
          borderBottom: isLast ? undefined : "1px solid #e8e8e5",
          borderLeft: "3px solid #e8601a",
          backgroundColor: "#fffcfa",
        }}
      >
        {/* AI icon */}
        <Sparkles className="h-3.5 w-3.5 shrink-0" style={{ color: "#e8601a" }} />

        {/* Content */}
        <div className="min-w-0 flex-1 flex items-center gap-2">
          <span
            className="font-semibold truncate"
            style={{
              fontFamily: "var(--font-fraunces)",
              fontSize: "13px",
              color: "#111113",
            }}
          >
            {item.projectName ?? "Unknown Project"}
          </span>
          {isUrgent && (
            <span
              className="inline-flex items-center rounded px-1 py-0.5 text-[10px] font-semibold leading-none"
              style={{
                backgroundColor: urgency === "CRITICAL" ? "#fff1f2" : "#fff8f0",
                color: urgency === "CRITICAL" ? "#dc2626" : "#d97706",
              }}
            >
              {urgency}
            </span>
          )}
        </div>

        {/* Version + timestamp */}
        <div className="flex items-center gap-3 shrink-0">
          <VersionChip version={sr.version} />
          <span
            className="whitespace-nowrap"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#9ca3af",
            }}
          >
            {timeAgo(getTimeStr({ kind: "semantic", data: sr }))}
          </span>
        </div>
      </Link>
    );
  }

  // Raw release
  const release = item.data;

  return (
    <Link
      href={`/releases/${release.id}`}
      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
      style={{
        borderBottom: isLast ? undefined : "1px solid #e8e8e5",
      }}
    >
      {/* Provider icon */}
      {item.provider ? (
        <ProviderIcon provider={item.provider} />
      ) : (
        <div className="h-3.5 w-3.5 shrink-0" />
      )}

      {/* Content */}
      <div className="min-w-0 flex-1 flex items-center gap-2">
        <span
          className="truncate"
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "13px",
            color: "#6b7280",
          }}
        >
          {item.repository ?? release.source_id.slice(0, 12)}
        </span>
        {item.projectName && (
          <span
            className="truncate"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#9ca3af",
            }}
          >
            · {item.projectName}
          </span>
        )}
      </div>

      {/* Version + timestamp */}
      <div className="flex items-center gap-3 shrink-0">
        <VersionChip version={release.version} />
        <span
          className="whitespace-nowrap"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "12px",
            color: "#9ca3af",
          }}
        >
          {timeAgo(release.released_at ?? release.created_at)}
        </span>
      </div>
    </Link>
  );
}

// web/components/dashboard/release-trend-chart.tsx
"use client";

import { useState } from "react";
import useSWR from "swr";
import { system } from "@/lib/api/client";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid,
} from "recharts";
import type { TrendBucket } from "@/lib/api/types";

type Granularity = "daily" | "weekly" | "monthly";

const RANGE_OPTIONS = [
  { label: "7d", days: 7, granularity: "daily" as Granularity },
  { label: "30d", days: 30, granularity: "daily" as Granularity },
  { label: "90d", days: 90, granularity: "weekly" as Granularity },
  { label: "1y", days: 365, granularity: "monthly" as Granularity },
];

function formatPeriod(period: string, granularity: Granularity): string {
  const d = new Date(period + "T00:00:00");
  switch (granularity) {
    case "daily":
      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
    case "weekly":
      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
    case "monthly":
      return d.toLocaleDateString("en-US", { month: "short", year: "2-digit" });
  }
}

export function ReleaseTrendChart() {
  const [rangeIdx, setRangeIdx] = useState(0);
  const range = RANGE_OPTIONS[rangeIdx];

  const { data, isLoading } = useSWR(
    `trend-${range.granularity}-${range.days}`,
    () => system.trend(range.granularity, range.days)
  );

  const buckets: TrendBucket[] = data?.data?.buckets ?? [];

  const chartData = buckets.map((b) => ({
    ...b,
    label: formatPeriod(b.period, range.granularity),
  }));

  return (
    <div
      className="flex flex-col rounded-lg bg-white px-5 py-4"
      style={{ border: "1px solid #e8e8e5", height: "280px" }}
    >
      <div className="flex items-center justify-between">
        <p
          className="text-xs uppercase tracking-[0.08em]"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "12px",
            color: "#6b7280",
          }}
        >
          Release Trend
        </p>
        <div className="flex gap-1">
          {RANGE_OPTIONS.map((opt, idx) => (
            <button
              key={opt.label}
              onClick={() => setRangeIdx(idx)}
              className="rounded px-2 py-0.5 text-xs font-medium transition-colors"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "11px",
                backgroundColor:
                  rangeIdx === idx ? "#111113" : "transparent",
                color: rangeIdx === idx ? "#ffffff" : "#6b7280",
                border:
                  rangeIdx === idx
                    ? "1px solid #111113"
                    : "1px solid #e8e8e5",
              }}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      <div className="relative mt-3 flex-1" style={{ minHeight: "100px" }}>
        {isLoading ? (
          <div
            className="flex h-full items-center justify-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : chartData.length === 0 ? (
          <div
            className="flex h-full items-center justify-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#b0b0a8",
            }}
          >
            No data yet
          </div>
        ) : (
          <div className="absolute inset-0">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={chartData}
                margin={{ top: 4, right: 0, bottom: 0, left: -20 }}
                barGap={1}
                barCategoryGap="20%"
              >
                <CartesianGrid
                  strokeDasharray="3 3"
                  stroke="#f0f0ed"
                  vertical={false}
                />
                <XAxis
                  dataKey="label"
                  tick={{ fontSize: 10, fill: "#b0b0a8" }}
                  tickLine={false}
                  axisLine={{ stroke: "#e8e8e5" }}
                  interval="preserveStartEnd"
                />
                <YAxis
                  tick={{ fontSize: 10, fill: "#b0b0a8" }}
                  tickLine={false}
                  axisLine={false}
                  allowDecimals={false}
                />
                <Tooltip
                  contentStyle={{
                    fontFamily: "var(--font-dm-sans)",
                    fontSize: "12px",
                    borderRadius: "6px",
                    border: "1px solid #e8e8e5",
                    boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
                  }}
                  labelStyle={{ fontWeight: 600, color: "#111113" }}
                  cursor={{ fill: "rgba(0,0,0,0.03)" }}
                />
                <Bar
                  dataKey="releases"
                  name="Releases"
                  fill="#e8601a"
                  radius={[2, 2, 0, 0]}
                  maxBarSize={20}
                />
                <Bar
                  dataKey="semantic_releases"
                  name="AI Reports"
                  fill="#f4a261"
                  radius={[2, 2, 0, 0]}
                  maxBarSize={20}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>
    </div>
  );
}

