// web/components/dashboard/stats-cards.tsx
"use client";

import useSWR from "swr";
import { system } from "@/lib/api/client";
import { FolderKanban, TrendingUp } from "lucide-react";
import type { LucideIcon } from "lucide-react";

interface StatItem {
  label: string;
  value: number | string;
  icon: LucideIcon;
}

export function StatsCards() {
  const { data, isLoading } = useSWR("stats", () => system.stats());

  const stats = data?.data;

  const items: StatItem[] = [
    { label: "Projects Tracked", value: stats?.total_projects ?? "\u2014", icon: FolderKanban },
    { label: "Releases This Week", value: stats?.releases_this_week ?? "\u2014", icon: TrendingUp },
  ];

  return (
    <div className="grid grid-cols-2 gap-4">
      {items.map((item) => (
        <div
          key={item.label}
          className="relative rounded-lg bg-white px-5 py-4"
          style={{ border: "1px solid #e8e8e5" }}
        >
          <item.icon
            className="absolute right-4 top-4 h-4 w-4"
            style={{ color: "#b0b0a8" }}
          />
          <p
            className="text-xs uppercase tracking-[0.08em]"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#6b7280",
            }}
          >
            {item.label}
          </p>
          <p
            className="mt-1 font-bold"
            style={{
              fontFamily: "var(--font-fraunces)",
              fontSize: "32px",
              lineHeight: 1.1,
              color: "#111113",
            }}
          >
            {isLoading ? "\u00B7\u00B7\u00B7" : item.value}
          </p>
        </div>
      ))}
    </div>
  );
}

const chartData = buckets.map((b) => ({
  ...b,
  label: formatPeriod(b.period, range.granularity),
}));

return (
  <div
    className="flex flex-col rounded-lg bg-white px-5 py-4"
    style={{ border: "1px solid #e8e8e5", height: "336px" }}
  >
    <div className="flex items-center justify-between">
      <p
        className="text-xs uppercase tracking-[0.08em]"
        style={{
          fontFamily: "var(--font-dm-sans)",
          fontSize: "12px",
          color: "#6b7280",
        }}
      >
        Release Trend
      </p>
      <div className="flex gap-1">
        {RANGE_OPTIONS.map((opt, idx) => (
          <button
            key={opt.label}
            onClick={() => setRangeIdx(idx)}
            className="rounded px-2 py-0.5 text-xs font-medium transition-colors"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "11px",
              backgroundColor:
                rangeIdx === idx ? "#111113" : "transparent",
              color: rangeIdx === idx ? "#ffffff" : "#6b7280",
              border:
                rangeIdx === idx
                  ? "1px solid #111113"
                  : "1px solid #e8e8e5",
            }}
          >
            {opt.label}

  return null; // Empty state handled by parent
}

return (
